#pragma once

#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <cuda_runtime.h>

// Kernel launch configuration optimized for A800
constexpr int BLOCK_SIZE = 256;
constexpr int HIDDEN_SIZE = 7168;
constexpr float RMS_EPS = 1e-6f;

extern "C" {

/**
 * Fused Add + RMSNorm CUDA kernel
 * 
 * Computes: output = (hidden_states + residual) * weight / rms_norm
 * 
 * @param hidden_states Input hidden states [batch_size, hidden_size]
 * @param residual Residual input [batch_size, hidden_size]
 * @param weight RMSNorm weight [hidden_size]
 * @param output Output tensor [batch_size, hidden_size]
 * @param batch_size Number of sequences in batch
 * @param hidden_size Hidden dimension (fixed at 7168)
 * @param eps RMSNorm epsilon value
 */
__global__ void fused_add_rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    float eps);

/**
 * Host function to launch the fused Add + RMSNorm kernel
 * 
 * @param hidden_states Input hidden states pointer
 * @param residual Residual input pointer
 * @param weight RMSNorm weight pointer
 * @param output Output tensor pointer
 * @param batch_size Number of sequences in batch
 * @param hidden_size Hidden dimension (fixed at 7168)
 * @param eps RMSNorm epsilon value
 * @param stream CUDA stream for asynchronous execution
 */
void fused_add_rmsnorm_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    float eps,
    cudaStream_t stream = 0);

} // extern "C"

#include "kernel.h"
#include <device_launch_parameters.h>

// Block size optimized for A800 (SM90 architecture)
// 256 threads per block provides good occupancy on A800
constexpr int BLOCK_SIZE = 256;
constexpr int HIDDEN_SIZE = 7168;
constexpr float RMS_EPS = 1e-6f;

/**
 * Fused Add + RMSNorm CUDA kernel optimized for A800
 * 
 * Algorithm:
 * 1. Load hidden_states + residual into shared memory (coalesced access)
 * 2. Compute variance (sum of squares) with parallel reduction
 * 3. Normalize and apply weight in second pass
 * 
 * Optimizations for A800:
 * - Uses shared memory to avoid redundant global memory reads
 * - Coalesced memory access patterns
 * - Parallel reduction for variance computation
 * - Efficient BFLOAT16 conversions
 */
__global__ void fused_add_rmsnorm_kernel(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    float eps) {

    // Each block processes one row (one sample in batch)
    int row = blockIdx.x;
    if (row >= batch_size) return;

    // Shared memory for one row of hidden states
    // 7168 * 2 bytes = 14336 bytes (fits in A800's 192KB shared memory per SM)
    extern __shared__ __nv_bfloat16 shared_mem[];
    __nv_bfloat16* x = shared_mem;

    int tid = threadIdx.x;

    // First pass: Load hidden_states + residual into shared memory
    // Each thread loads multiple elements for better memory throughput
    for (int i = tid; i < hidden_size; i += BLOCK_SIZE) {
        int idx = row * hidden_size + i;
        float h = __bfloat162float(hidden_states[idx]);
        float r = __bfloat162float(residual[idx]);
        x[i] = __float2bfloat16(h + r);
    }
    __syncthreads();

    // Second pass: Compute sum of squares with parallel reduction
    float sum_sq = 0.0f;
    for (int i = tid; i < hidden_size; i += BLOCK_SIZE) {
        float val = __bfloat162float(x[i]);
        sum_sq += val * val;
    }

    // Parallel reduction to compute total sum of squares
    __shared__ float sum_sq_shared[BLOCK_SIZE];
    sum_sq_shared[tid] = sum_sq;
    __syncthreads();

    // Tree-based reduction
    for (int stride = BLOCK_SIZE / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            sum_sq_shared[tid] += sum_sq_shared[tid + stride];
        }
        __syncthreads();
    }

    // Compute inverse RMS
    float mean_sq = sum_sq_shared[0] / static_cast<float>(hidden_size);
    float inv_rms = rsqrtf(mean_sq + eps);

    // Broadcast inv_rms to all threads
    __shared__ float inv_rms_shared;
    if (tid == 0) {
        inv_rms_shared = inv_rms;
    }
    __syncthreads();

    // Third pass: Normalize and apply weight
    for (int i = tid; i < hidden_size; i += BLOCK_SIZE) {
        int idx = row * hidden_size + i;
        float val = __bfloat162float(x[i]);
        float w = __bfloat162float(weight[i]);
        float out = val * inv_rms_shared * w;
        output[idx] = __float2bfloat16(out);
    }
}

/**
 * Host function to launch the fused Add + RMSNorm kernel
 * 
 * Calculates appropriate launch configuration and launches the kernel
 * with proper shared memory allocation.
 */
void fused_add_rmsnorm_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* residual,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    int hidden_size,
    float eps,
    cudaStream_t stream) {

    // Shared memory size for one row (7168 BF16 elements)
    size_t shared_mem_size = hidden_size * sizeof(__nv_bfloat16);

    // Launch configuration: one block per row in batch
    int blocks = batch_size;
    int threads = BLOCK_SIZE;

    // Launch kernel with shared memory
    fused_add_rmsnorm_kernel<<<blocks, threads, shared_mem_size, stream>>>(
        hidden_states,
        residual,
        weight,
        output,
        batch_size,
        hidden_size,
        eps);

    // Check for launch errors (non-blocking)
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        // Error will be reported by caller
    }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include "kernel.h"
#include <stdexcept>
#include <string>

/**
 * Validates tensor properties for the fused Add + RMSNorm operation
 * 
 * @param hidden_states Input hidden states tensor
 * @param residual Residual input tensor
 * @param weight RMSNorm weight tensor
 * @throws std::runtime_error if validation fails
 */
void validate_tensors(const torch::Tensor& hidden_states,
                      const torch::Tensor& residual,
                      const torch::Tensor& weight) {
    // Check device
    if (!hidden_states.device().is_cuda()) {
        throw std::runtime_error("hidden_states must be on CUDA device");
    }
    if (!residual.device().is_cuda()) {
        throw std::runtime_error("residual must be on CUDA device");
    }
    if (!weight.device().is_cuda()) {
        throw std::runtime_error("weight must be on CUDA device");
    }

    // Check dtype (BFLOAT16)
    if (hidden_states.dtype() != torch::kBFloat16) {
        throw std::runtime_error("hidden_states must be BFLOAT16");
    }
    if (residual.dtype() != torch::kBFloat16) {
        throw std::runtime_error("residual must be BFLOAT16");
    }
    if (weight.dtype() != torch::kBFloat16) {
        throw std::runtime_error("weight must be BFLOAT16");
    }

    // Check shapes
    auto hidden_shape = hidden_states.sizes();
    auto residual_shape = residual.sizes();
    auto weight_shape = weight.sizes();

    if (hidden_shape.size() != 2) {
        throw std::runtime_error("hidden_states must be 2D tensor");
    }
    if (residual_shape.size() != 2) {
        throw std::runtime_error("residual must be 2D tensor");
    }
    if (weight_shape.size() != 1) {
        throw std::runtime_error("weight must be 1D tensor");
    }

    int batch_size = hidden_shape[0];
    int hidden_size = hidden_shape[1];

    if (residual_shape[0] != batch_size) {
        throw std::runtime_error("residual batch size must match hidden_states");
    }
    if (residual_shape[1] != hidden_size) {
        throw std::runtime_error("residual hidden size must match hidden_states");
    }
    if (weight_shape[0] != hidden_size) {
        throw std::runtime_error("weight size must match hidden_size");
    }

    // Check fixed hidden size
    if (hidden_size != HIDDEN_SIZE) {
        throw std::runtime_error("hidden_size must be " + std::to_string(HIDDEN_SIZE));
    }
}

/**
 * Fused Add + RMSNorm operation
 * 
 * Computes: output = (hidden_states + residual) * weight / rms_norm
 * 
 * @param hidden_states Input hidden states [batch_size, hidden_size]
 * @param residual Residual input [batch_size, hidden_size]
 * @param weight RMSNorm weight [hidden_size]
 * @return Output tensor [batch_size, hidden_size]
 */
torch::Tensor run(const torch::Tensor& hidden_states,
                  const torch::Tensor& residual,
                  const torch::Tensor& weight) {

    // Validate inputs
    validate_tensors(hidden_states, residual, weight);

    // Extract tensor properties
    int batch_size = hidden_states.size(0);
    int hidden_size = hidden_states.size(1);

    // Create output tensor with same properties as input
    auto output = torch::empty_like(hidden_states);

    // Get raw pointers
    const __nv_bfloat16* hidden_ptr = hidden_states.data_ptr<__nv_bfloat16>();
    const __nv_bfloat16* residual_ptr = residual.data_ptr<__nv_bfloat16>();
    const __nv_bfloat16* weight_ptr = weight.data_ptr<__nv_bfloat16>();
    __nv_bfloat16* output_ptr = output.data_ptr<__nv_bfloat16>();

    // Get current CUDA stream
    auto stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    fused_add_rmsnorm_launch(
        hidden_ptr,
        residual_ptr,
        weight_ptr,
        output_ptr,
        batch_size,
        hidden_size,
        RMS_EPS,
        stream);

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + 
                                 cudaGetErrorString(err));
    }

    return output;
}

/**
 * PyBind11 module definition for Python bindings
 */
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, 
          "Fused Add + RMSNorm operation\n"
          "Computes: output = (hidden_states + residual) * weight / rms_norm\n"
          "\n"
          "Args:\n"
          "  hidden_states (torch.Tensor): Input hidden states [batch_size, 7168], BFLOAT16\n"
          "  residual (torch.Tensor): Residual input [batch_size, 7168], BFLOAT16\n"
          "  weight (torch.Tensor): RMSNorm weight [7168], BFLOAT16\n"
          "\n"
          "Returns:\n"
          "  torch.Tensor: Output tensor [batch_size, 7168], BFLOAT16");
}
